---@class StructRedPoint
local StructRedPoint = LxClass("StructRedPoint", nil)

function StructRedPoint:StructRedPoint()
    self.redPointRefId = nil --//红点refId
    self.count = 0         --//红点计数（0=通知去掉红点；> 0 通知显示红点）
    self.moreinfo = nil      --//其他标注信息
    self.clicked = false

    self.idMap ={}

    self.adCount = 0
end

function StructRedPoint:CreateByPb(pb)
    self.redPointRefId = pb.redPointRefId
    self.defaultInfo = pb.moreinfo
    if gModelRedPoint:IsMultiIdRedPoint(self.redPointRefId) then
        local count = pb.count
        local idList = {}
        local isActivity = gModelRedPoint:IsActivityRedPoint(self.redPointRefId)
        if isActivity then
            local activityList = pb.activityList or {}
            for i, v in ipairs(activityList) do
                local sid = v.sid
                table.insert(idList,sid)
            end
        else
            idList = self:GetActivityIds(pb.moreinfo)
        end

        local value = nil
        if count>0 then
            value = true
        end
        if gModelRedPoint:IsRedDirectTakeList(self.redPointRefId) then
            self.idMap = {}
        end

        for k,v in ipairs(idList) do
            self.idMap[v] = value
        end
        self.count = count
    else
        self.count = pb.count
        self.moreinfo = pb.moreinfo
    end
end

function StructRedPoint:SetClicked()
    self.clicked = true
    self.count = 0
end

function StructRedPoint:SetMultiRedClicked(sid)
    if gModelRedPoint:IsMultiIdRedPoint(self.redPointRefId) then
        self.idMap[sid] = nil
    end
end

function StructRedPoint:CreateByClient(refId,showRed)
    self.redPointRefId = refId
    self.count = showRed and 1 or 0
end

function StructRedPoint:GetActivityIds(str)
    local list = {}
    if string.isempty(str) then
        return list
    end

    local strs = string.split(str,"|")
    for k,v in ipairs(strs) do
        local id = tonumber(v)
        if id then
           table.insert(list,id)
        end
    end
    return list
end

function StructRedPoint:GetActivityRedMap()
    return self.idMap
end

function StructRedPoint:CreateByAds(refId,bShow)
    self.redPointRefId = refId
    self.adCount = bShow and 1 or 0
end

function StructRedPoint:SetAdsShopData(refId,shopIdStr)
    self.redPointRefId = refId

    local idList = self:GetActivityIds(shopIdStr)
    local idMap = self.idMap or {}
    for k,v in ipairs(idList) do
        idMap[v] = true
    end
    self.idMap = idMap
end

return StructRedPoint